const p = path.join(__dirname, '..', 'data', 'b1.json');
const data = JSON.parse(fs.readFileSync(p, 'utf8'));
let added = 0, missing = 0;
for (const item of data) {
  if (!item.ex || item.ex_tr) continue;
  if (T[item.ex]) { item.ex_tr = T[item.ex]; added++; }
  else { missing++; }
}
fs.writeFileSync(p, JSON.stringify(data, null, 0).replace(/},{/g, '},\n{') + '\n');
console.log(`B1 batch 2: eklenen ${added}, kalan ${missing}`);
